## Shell command execution and output capture for the get tool.
##
## :Author: WaterRun
## :GitHub: https://github.com/Water-Run/get
## :Date: 2026-04-17
## :File: exec.nim
## :License: AGPL-3.0
##
## This module provides procedures to execute shell commands
## generated by the LLM, capture their combined stdout/stderr
## output, and present interactive manual-confirm gating.
## Commands are run through the configured shell via startProcess
## with the bundled bin/ directory prepended to PATH so that
## shipped tools are available to generated commands.
##
## Forbidden-command-pattern validation lives in utils.nim so
## that the config module can reference it without a circular
## dependency.

{.experimental: "strictFuncs".}

import std/[envvars, os, osproc, strtabs, streams,
            strformat, strutils]

import style
import utils

# ---------------------------------------------------------------------------
# Types
# ---------------------------------------------------------------------------

## Encapsulates the result of a shell command execution.
type
  ExecResult* = object
    output*: string   ## Combined stdout and stderr output.
    exitCode*: int    ## Process exit code (0 = success).

# ---------------------------------------------------------------------------
# Private helpers
# ---------------------------------------------------------------------------

## Builds the argument list for invoking a command through the
## given shell.
##
## :param shell: Shell executable name or path.
## :param command: The command string to execute.
## :returns: A seq of shell arguments.
func implBuildShellArgs(
  shell: string,
  command: string
): seq[string] =
  let lower = toLowerAscii(shell)
  if lower.contains("powershell") or
      lower.contains("pwsh"):
    result = @[
      "-NoProfile", "-NonInteractive",
      "-Command", command]
  elif lower.contains("cmd"):
    result = @["/C", command]
  else:
    result = @["-c", command]

## Creates a StringTableRef with binDir prepended to PATH.
## Returns nil when binDir is empty or does not exist.
##
## :param binDir: Absolute path to the bundled bin directory.
## :returns: A modified environment table, or nil.
proc implBuildEnv(binDir: string): StringTableRef =
  if binDir.len == 0 or not dirExists(binDir):
    return nil
  when defined(windows):
    var env = newStringTable(modeCaseInsensitive)
  else:
    var env = newStringTable(modeCaseSensitive)
  for key, val in envPairs():
    env[key] = val
  var curPath = ""
  if env.hasKey("PATH"):
    curPath = env["PATH"]
  when defined(windows):
    env["PATH"] = binDir & ";" & curPath
  else:
    env["PATH"] = binDir & ":" & curPath
  result = env

## Reads a single line from the controlling terminal.  Tries
## stdin first, then falls back to /dev/tty (Unix) or CONIN$
## (Windows).
##
## :returns: The trimmed user input, or empty on failure.
proc implReadTerminalLine(): string =
  try:
    result = stdin.readLine()
    return
  except IOError, EOFError:
    discard
  try:
    when defined(windows):
      let tty = open("CONIN$", fmRead)
    else:
      let tty = open("/dev/tty", fmRead)
    try:
      result = tty.readLine()
    finally:
      tty.close()
    return
  except IOError, EOFError, OSError:
    discard
  result = ""

# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

## Displays the command and reads a y/N confirmation.  Returns
## true only when the user types "y" (case-insensitive).
##
## :param command: The command awaiting confirmation.
## :param sk: The active output style.
## :param showCommand: Whether to display the command.
## :returns: true if the user confirms with "y".
##
## .. code-block:: nim
##   runnableExamples:
##     discard
proc confirmExecution*(
  command: string,
  sk: StyleKind = skSimp,
  showCommand: bool = true
): bool =
  case sk
  of skSimp:
    if showCommand:
      stderr.write(
        "execute: " & command &
        "\nconfirm? (y/N): ")
    else:
      stderr.write("confirm? (y/N): ")
  of skVivid:
    if showCommand:
      stderr.write(
        ANSI_MAGENTA &
        "\xe2\x9d\xaf " & ANSI_BOLD &
        command & ANSI_RESET &
        "\n" & ANSI_YELLOW & ANSI_BOLD &
        "confirm? (y/N): " & ANSI_RESET)
    else:
      stderr.write(
        ANSI_YELLOW & ANSI_BOLD &
        "confirm? (y/N): " & ANSI_RESET)
  stderr.flushFile()
  stdout.flushFile()
  let response = implReadTerminalLine()
  result = toLowerAscii(response.strip()) == "y"

## Executes a command string through the specified shell and
## returns the captured combined output together with the exit
## code.
##
## :param command: The command to execute.
## :param shell: Shell executable name or path.
## :param binDir: Optional bundled-binary directory to prepend
##                to PATH.
## :returns: An ExecResult with captured output and exit code.
## :raises: GetError: If the shell process cannot be started.
##
## .. code-block:: nim
##   runnableExamples:
##     discard
proc executeCommand*(
  command: string,
  shell: string,
  binDir: string = ""
): ExecResult =
  let args = implBuildShellArgs(shell, command)
  let env = implBuildEnv(binDir)
  var p: Process
  try:
    p = startProcess(
      shell,
      args = args,
      env = env,
      options = {poStdErrToStdOut, poUsePath})
  except OSError as e:
    raise newException(GetError,
      fmt"cannot start shell '{shell}': {e.msg}")
  let output = p.outputStream.readAll()
  let exitCode = p.waitForExit()
  p.close()
  result = ExecResult(
    output: output,
    exitCode: exitCode)